6104 // This is the recursive version of BuildSubAggregate. It takes a few different
6105 // arguments. Idxs is the index within the nested struct From that we are
6106 // looking at now (which is of type IndexedType). IdxSkip is the number of
6107 // indices from Idxs that should be left out when inserting into the resulting
6108 // struct. To is the result struct built so far, new insertvalue instructions
6109 // build on that.
6110 static Value *BuildSubAggregate(Value *From, Value *To, Type *IndexedType,
6111                                 SmallVectorImpl<unsigned> &Idxs,
6112                                 unsigned IdxSkip,
6113                                 BasicBlock::iterator InsertBefore) {
6114   StructType *STy = dyn_cast<StructType>(IndexedType);
6115   if (STy) {
6116     // Save the original To argument so we can modify it
6117     Value *OrigTo = To;
6118     // General case, the type indexed by Idxs is a struct
6119     for (unsigned i = 0, e = STy->getNumElements(); i != e; ++i) {
6120       // Process each struct element recursively
6121       Idxs.push_back(i);
6122       Value *PrevTo = To;
6123       To = BuildSubAggregate(From, To, STy->getElementType(i), Idxs, IdxSkip,
6124                              InsertBefore);
6125       Idxs.pop_back();
6126       if (!To) {
6127         // Couldn't find any inserted value for this index? Cleanup
6128         while (PrevTo != OrigTo) {
6129           InsertValueInst* Del = cast<InsertValueInst>(PrevTo);
6130           PrevTo = Del->getAggregateOperand();
6131           Del->eraseFromParent();
6132         }
6133         // Stop processing elements
6134         break;
6135       }
6136     }
6137     // If we successfully found a value for each of our subaggregates
6138     if (To)
6139       return To;
6140   }
6141   // Base case, the type indexed by SourceIdxs is not a struct, or not all of
6142   // the struct's elements had a value that was inserted directly. In the latter
6143   // case, perhaps we can't determine each of the subelements individually, but
6144   // we might be able to find the complete struct somewhere.
6145 
6146   // Find the value that is at that particular spot
6147   Value *V = FindInsertedValue(From, Idxs);
6148 
6149   if (!V)
6150     return nullptr;
6151 
6152   // Insert the value in the new (sub) aggregate
6153   return InsertValueInst::Create(To, V, ArrayRef(Idxs).slice(IdxSkip), "tmp",
6154                                  InsertBefore);
6155 }
